// ═══════════════════════════════════════════════════════════════════════════
// 🔵 INFO: Load Configuration from EEPROM
// ═══════════════════════════════════════════════════════════════════════════

bool loadConfig(SystemConfig &config)
{
  // 🔵 INFO: Read configuration structure from EEPROM
  // ⚪ NOTE: EEPROM.get() handles multi-byte reads automatically
  EEPROM.get(EEPROM_CONFIG_START, config);

  // 🔵 INFO: Validate magic number to detect uninitialized EEPROM
  // ⚪ NOTE: If invalid, we'll use defaults instead
  if (config.magicNumber != EEPROM_MAGIC_NUMBER)
  {
#ifdef DEBUG
    Serial.println(F("Storage: Invalid magic number, using defaults"));
#endif

    getDefaultConfig(config);
    saveConfig(config); // Save defaults for next boot
    return false;
  }

  // 🟠 WARNING: Version mismatch handling could be added here
  // ⚪ NOTE: For now, we trust the structure matches

#ifdef DEBUG
  Serial.println(F("Storage: Configuration loaded from EEPROM"));
  Serial.print(F("  - WiFi SSID: "));
  Serial.println(config.wifi.ssid);
  Serial.print(F("  - Debug Mode: "));
  Serial.println(config.debugMode ? "ON" : "OFF");
#endif

  return true;
}

// ═══════════════════════════════════════════════════════════════════════════
// 🔵 INFO: Save Configuration to EEPROM
// ═══════════════════════════════════════════════════════════════════════════

bool saveConfig(const SystemConfig &config)
{
  // 🔵 INFO: Write entire configuration structure to EEPROM
  // ⚪ NOTE: EEPROM.put() handles multi-byte writes and wear leveling
  // ⚪ PERFORMANCE: EEPROM writes are slow (~3ms per byte) but acceptable since
  //    configuration saves are infrequent (typically only via web interface).
  // ⚪ WARNING: EEPROM has limited write cycles (~100,000). Avoid frequent saves.
  EEPROM.put(EEPROM_CONFIG_START, config);

  // 🔵 INFO: Commit changes to flash memory
  // ⚪ NOTE: Required for ESP8266 to actually persist the data
  bool success = EEPROM.commit();

#ifdef DEBUG
  if (success)
  {
    Serial.println(F("Storage: Configuration saved to EEPROM"));
  }
  else
  {
    Serial.println(F("Storage: ERROR - Failed to save configuration"));
  }
#endif

  return success;
}

