void resetToDefaults(SystemConfig &config)
{
#ifdef DEBUG
  Serial.println(F("Storage: Performing factory reset"));
#endif

  // 🔵 INFO: Load default values into configuration
  getDefaultConfig(config);

  // 🔵 INFO: Persist defaults to EEPROM
  saveConfig(config);

#ifdef DEBUG
  Serial.println(F("Storage: Factory reset complete"));
#endif
}
